// src/utils/generadorPdf.js
import pdfMake from "pdfmake/build/pdfmake";
import * as pdfFontsModule from "pdfmake/build/vfs_fonts";

const vfs = pdfFontsModule.pdfMake?.vfs || pdfFontsModule.default?.pdfMake?.vfs || pdfFontsModule.vfs;
pdfMake.vfs = vfs;

pdfMake.fonts = {
  Roboto: {
    normal: 'Roboto-Regular.ttf',
    bold: 'Roboto-Medium.ttf',
    italics: 'Roboto-Italic.ttf',
    bolditalics: 'Roboto-MediumItalic.ttf'
  }
};

export const formatearMoneda = (valor) => valor ? Number(valor).toLocaleString('en-US', {minimumFractionDigits: 2}) : '0.00';

export const numeroALetras = (numero) => {
  const unidades = (num) => {
    switch(num) {
      case 1: return 'UN'; case 2: return 'DOS'; case 3: return 'TRES'; case 4: return 'CUATRO'; case 5: return 'CINCO';
      case 6: return 'SEIS'; case 7: return 'SIETE'; case 8: return 'OCHO'; case 9: return 'NUEVE';
    }
    return '';
  };
  const decenas = (num) => {
    let decena = Math.floor(num/10); let unidad = num - (decena * 10);
    switch(decena) {
      case 1:
        switch(unidad) {
          case 0: return 'DIEZ'; case 1: return 'ONCE'; case 2: return 'DOCE'; case 3: return 'TRECE';
          case 4: return 'CATORCE'; case 5: return 'QUINCE'; default: return 'DIECI' + unidades(unidad);
        }
      case 2:
        switch(unidad) { case 0: return 'VEINTE'; default: return 'VEINTI' + unidades(unidad); }
      case 3: return decenasY('TREINTA', unidad); case 4: return decenasY('CUARENTA', unidad);
      case 5: return decenasY('CINCUENTA', unidad); case 6: return decenasY('SESENTA', unidad);
      case 7: return decenasY('SETENTA', unidad); case 8: return decenasY('OCHENTA', unidad);
      case 9: return decenasY('NOVENTA', unidad); case 0: return unidades(unidad);
    }
  };
  const decenasY = (strSin, numUnidades) => { return numUnidades > 0 ? strSin + ' Y ' + unidades(numUnidades) : strSin; };
  const centenas = (num) => {
    let centenas = Math.floor(num / 100); let decs = num - (centenas * 100);
    switch(centenas) {
      case 1: return decs > 0 ? 'CIENTO ' + decenas(decs) : 'CIEN';
      case 2: return 'DOSCIENTOS ' + decenas(decs); case 3: return 'TRESCIENTOS ' + decenas(decs);
      case 4: return 'CUATROCIENTOS ' + decenas(decs); case 5: return 'QUINIENTOS ' + decenas(decs);
      case 6: return 'SEISCIENTOS ' + decenas(decs); case 7: return 'SETECIENTOS ' + decenas(decs);
      case 8: return 'OCHOCIENTOS ' + decenas(decs); case 9: return 'NOVECIENTOS ' + decenas(decs);
    }
    return decenas(decs);
  };
  const seccion = (num, divisor, strSingular, strPlural) => {
    let cientos = Math.floor(num / divisor); let resto = num - (cientos * divisor); let letras = '';
    if (cientos > 0) letras = cientos > 1 ? centenas(cientos) + ' ' + strPlural : strSingular;
    return letras;
  };
  const miles = (num) => {
    let divisor = 1000; let cientos = Math.floor(num / divisor); let resto = num - (cientos * divisor);
    let strMiles = seccion(num, divisor, 'MIL', 'MIL'); let strCentenas = centenas(resto);
    return strMiles == '' ? strCentenas : strMiles + ' ' + strCentenas;
  };
  const millones = (num) => {
    let divisor = 1000000; let cientos = Math.floor(num / divisor); let resto = num - (cientos * divisor);
    let strMillones = seccion(num, divisor, 'UN MILLON', 'MILLONES'); let strMiles = miles(resto);
    return strMillones == '' ? strMiles : strMillones + ' ' + strMiles;
  };
  
  if (!numero || numero === 0) return 'CERO PESOS M/CTE';
  let enteros = Math.floor(numero);
  if (enteros == 1) return millones(enteros) + ' PESO M/CTE';
  return millones(enteros) + ' PESOS M/CTE';
};

// 🔥 Función auxiliar para obtener la etiqueta del tipo de documento
const etiquetaTipoDoc = (tipoDoc) => {
  switch(tipoDoc) {
    case 'NIT': return 'N.I.T:';
    case 'CC': return 'C.C:';
    case 'CE': return 'C.E:';
    case 'PPT': return 'P.P.T:';
    case 'PAS': return 'PAS:';
    default: return 'C.C:';
  }
};

export const generarPDF = (tipo, datos, ajustes, soloVista = false) => {
  // ⚠️ REEMPLAZA ESTO CON TU BASE64 REAL
    const logoBase64 = "data:image/png;base64,";

  
  const estilos = {
    header: { fontSize: 16, bold: true, alignment: 'center' },
    subheader: { fontSize: 12, bold: true, alignment: 'center', margin: [0, 0, 0, 10] },
    tableHeader: { bold: true, fontSize: 10, color: 'white', fillColor: '#cc0000', alignment: 'center', margin: [2, 2, 2, 2] },
    textoBold: { bold: true, fontSize: 10 },
    textoNormal: { fontSize: 10 },
    textoPequeno: { fontSize: 9 }
  };

  let documentDefinition = {};

  if (tipo === 'cotizacion') {
    const filasItems = [
      [{ text: 'CANT.', style: 'tableHeader' }, { text: 'DESCRIPCION', style: 'tableHeader' }, { text: 'VALOR TOTAL', style: 'tableHeader' }]
    ];
    
    if(datos.items && datos.items.length > 0) {
      datos.items.forEach(item => {
        filasItems.push([
          { text: item.cantidad?.toString() || '1', alignment: 'center', style: 'textoBold' }, 
          { text: item.descripcion || '', style: 'textoNormal' }, 
          { text: '$ ' + formatearMoneda(item.valor), alignment: 'right', style: 'textoNormal' }
        ]);
      });
    }

    const faltantes = 8 - (datos.items?.length || 0);
    for(let i=0; i < faltantes; i++) {
      filasItems.push(['', '', { text: '$ 0.00', alignment: 'right', style: 'textoNormal' }]);
    }

    const tipoDocEtiqueta = etiquetaTipoDoc(datos.tipoDoc);
    const tipoDocNumero = datos.documento || '';

    // 🔥 HEADER
    const headerContent = [];
    
    if (logoBase64) {
  headerContent.push({
    columns: [
      {
        width: 95,
        stack: [
          { text: '', margin: [0, -15, 0, 0] },
          { 
            image: logoBase64,
            fit: [80, 80],
            alignment: 'center',
            margin: [0, 0, 0, 0]
          },
          { text: '', margin: [0, 0, 0, 0] }
        ]
      },
      {
        width: '*',
        stack: [
          { text: 'CARPINTERIA SAGRADA FAMILIA', style: 'header', alignment: 'center', margin: [0, 0, 0, 0] },
          { text: 'RAFAEL JOSE PEREZ LEON', style: 'subheader', alignment: 'center', margin: [0, 2, 0, 0] }
        ],
        margin: [0, 14, 0, 0]
      },
      {
        width: 'auto',
        table: {
          widths: ['auto', 'auto'],
          body: [
            [
              { text: 'Fecha:', bold: true, fontSize: 9, color: 'white', fillColor: '#cc0000', alignment: 'center', margin: [4, 2, 4, 2] }, 
              { text: datos.fechaCreacionStr || '', alignment: 'center', style: 'textoBold', margin: [4, 2, 4, 2] }
            ],
            [
              { text: 'Cotización Nº', bold: true, fontSize: 9, color: 'white', fillColor: '#cc0000', alignment: 'center', margin: [4, 2, 4, 2] }, 
              { text: datos.numero || '', alignment: 'center', style: 'textoBold', margin: [4, 2, 4, 2] }
            ]
          ]
        },
        layout: {
          hLineWidth: () => 0.5,
          vLineWidth: () => 0.5,
          hLineColor: () => '#cc0000',
          vLineColor: () => '#cc0000'
        },
        margin: [0, 2, 0, 0]
      }
    ],
    columnGap: 12,
    margin: [0, 0, 0, 15]
  });
} else {
      headerContent.push({
        columns: [
          {
            width: '*',
            stack: [
              { text: 'CARPINTERIA SAGRADA FAMILIA', style: 'header', alignment: 'center' },
              { text: 'RAFAEL JOSE PEREZ LEON', style: 'subheader', alignment: 'center', margin: [0, 2, 0, 0] }
            ]
          },
          {
            width: 'auto',
            table: {
              widths: ['auto', 'auto'],
              body: [
                [
                  { text: 'Fecha:', bold: true, fontSize: 9, color: 'white', fillColor: '#cc0000', alignment: 'center', margin: [4, 2, 4, 2] }, 
                  { text: datos.fechaCreacionStr || '', alignment: 'center', style: 'textoBold', margin: [4, 2, 4, 2] }
                ],
                [
                  { text: 'Cotización Nº', bold: true, fontSize: 9, color: 'white', fillColor: '#cc0000', alignment: 'center', margin: [4, 2, 4, 2] }, 
                  { text: datos.numero || '', alignment: 'center', style: 'textoBold', margin: [4, 2, 4, 2] }
                ]
              ]
            },
            layout: {
              hLineWidth: () => 0.5,
              vLineWidth: () => 0.5,
              hLineColor: () => '#cc0000',
              vLineColor: () => '#cc0000'
            }
          }
        ],
        columnGap: 15,
        margin: [0, 0, 0, 15]
      });
    }

    documentDefinition = {
      content: [
        ...headerContent,
        
        // 🔥 Tabla de datos del cliente con tipo de documento como etiqueta
        {
          table: {
            widths: ['15%', '15%', '15%', '20%', '15%', '20%'],
            body: [
              [
                { text: 'Cliente:', style: 'tableHeader' }, 
                { text: datos.cliente || '', style: 'textoBold', colSpan: 3 }, {}, {}, 
                { text: tipoDocEtiqueta, style: 'tableHeader' }, 
                { text: tipoDocNumero, style: 'textoBold' }
              ],
              [
                { text: 'Dirección:', style: 'tableHeader' }, 
                { text: datos.direccion || '', style: 'textoBold', colSpan: 3 }, {}, {}, 
                { text: 'Torre:', style: 'tableHeader' }, 
                { text: datos.torre || '', style: 'textoBold' }
              ],
              [
                { text: 'Apto:', style: 'tableHeader' }, 
                { text: datos.apto || '', style: 'textoBold' }, 
                { text: 'Barrio:', style: 'tableHeader' }, 
                { text: datos.barrio || '', style: 'textoBold' }, 
                { text: 'Contacto:', style: 'tableHeader' }, 
                { text: datos.contacto || '', style: 'textoBold' }
              ]
            ]
          },
          margin: [0, 0, 0, 10]
        },
        
        { table: { widths: ['10%', '65%', '25%'], body: filasItems }, margin: [0, 0, 0, 10] },
        
        {
          table: {
            widths: ['75%', '25%'],
            body: [
              [{ text: 'TOTAL:', style: 'tableHeader', alignment: 'right' }, 
               { text: '$ ' + formatearMoneda(datos.total), alignment: 'right', bold: true, color: '#cc0000', fontSize: 12 }]
            ]
          },
          margin: [0, 0, 0, 15]
        },
        
        { text: 'OBSERVACIONES: ' + (datos.observaciones || ''), color: '#cc0000', bold: true, italic: true, fontSize: 10, margin: [0, 0, 0, 5] },
        { text: '"PRESUPUESTO NO INCLUYE IVA, NI RETENCIONES" INCLUYE TRANSPORTE E INSTALACIÓN.', style: 'textoBold', margin: [0, 0, 0, 5] },
        { text: 'CONDICIONES GENERALES:', style: 'textoBold', decoration: 'underline', margin: [0, 0, 0, 5] },
        {
          ul: [
            { text: [{ text: 'Tiempo de entrega: ', bold: true }, ajustes.tiempoEntrega] },
            { text: [{ text: 'Condiciones de pago: ', bold: true }, ajustes.condicionesPago] },
            { text: [{ text: 'Forma de pago: ', bold: true }, ajustes.formaPago] },
            { text: [{ text: 'Garantía: ', bold: true }, ajustes.garantia] }
          ],
          style: 'textoPequeno'
        }
      ],
      styles: estilos
    };
  } else {
    // 🔥 CUENTA DE COBRO - DISEÑO ORIGINAL COMPACTADO
    const cobroContent = [];
    
    if (logoBase64) {
      cobroContent.push({
        columns: [
          {
            width: 75,
            image: logoBase64,
            fit: [70, 70],
            alignment: 'center',
            margin: [0, 0, 0, 0]
          },
          {
            width: '*',
            text: datos.fechaCiudad || '',
            alignment: 'right',
            fontSize: 9,
            color: '#555',
            margin: [0, 8, 0, 0]
          }
        ],
        columnGap: 10,
        margin: [0, 0, 0, 25]
      });
    } else {
      cobroContent.push({
        text: datos.fechaCiudad || '',
        alignment: 'right',
        fontSize: 9,
        color: '#555',
        margin: [0, 0, 0, 25]
      });
    }

    documentDefinition = {
      defaultStyle: { fontSize: 11, lineHeight: 1.2 },
      content: [
        ...cobroContent,
        
        // Título
        { text: 'CUENTA DE COBRO', fontSize: 13, bold: true, alignment: 'center', margin: [0, 0, 0, 20] },
        
        // Datos del cliente (quien paga)
        { text: (datos.cliente || '').toUpperCase(), alignment: 'center', bold: true, fontSize: 11, margin: [0, 0, 0, 2] },
        (datos.tipoDoc && datos.documento) ? { 
          text: `${datos.tipoDoc} ${datos.documento}`.toUpperCase(), 
          alignment: 'center', 
          fontSize: 10,
          margin: [0, 0, 0, 2]
        } : {},
        { text: (datos.direccion || '').toUpperCase(), alignment: 'center', fontSize: 10, margin: [0, 0, 0, 20] },
        
        // DEBE A
        { text: 'DEBE A:', alignment: 'center', bold: true, fontSize: 10, margin: [0, 0, 0, 6] },
        { text: 'RAFAEL JOSÉ PÉREZ LEÓN', alignment: 'center', bold: true, fontSize: 11, margin: [0, 0, 0, 2] },
        { text: 'PASAPORTE: 112472838', alignment: 'center', fontSize: 10, margin: [0, 0, 0, 20] },
        
        // LA SUMA DE
        { text: 'LA SUMA DE:', alignment: 'center', bold: true, fontSize: 10, margin: [0, 0, 0, 6] },
        { text: `${(datos.montoLetras || '').toUpperCase()}`, alignment: 'center', bold: true, fontSize: 11, margin: [0, 0, 0, 2] },
        { text: `($ ${formatearMoneda(datos.total)})`, alignment: 'center', fontSize: 10, margin: [0, 0, 0, 20] },
        
        // POR CONCEPTO DE
        { text: 'POR CONCEPTO DE:', alignment: 'center', bold: true, fontSize: 10, margin: [0, 0, 0, 6] },
        { text: (datos.concepto || '').toUpperCase(), alignment: 'justify', fontSize: 10, lineHeight: 1.3, margin: [0, 0, 0, 25] },
        
        // Pago de servicios
        {
          columns: [
            { text: 'PAGO DE SERVICIOS', bold: true, fontSize: 10, width: 'auto' },
            { text: `$ ${formatearMoneda(datos.total)}`, bold: true, fontSize: 12, width: '*', alignment: 'right' }
          ],
          margin: [0, 0, 0, 35]
        },
        
        // 🔥 FIRMAS ALINEADAS PERFECTAMENTE
        {
          table: {
            widths: ['*', 30, '*'],
            body: [
              // Fila 1: Datos de cada firmante
              [
                {
                  stack: [
                    { text: (datos.cliente || '').toUpperCase(), bold: true, fontSize: 10, margin: [0, 0, 0, 2] },
                    (datos.tipoDoc && datos.documento) ? { text: `${datos.tipoDoc} ${datos.documento}`.toUpperCase(), fontSize: 9, margin: [0, 0, 0, 2] } : {},
                    { text: (datos.direccion || '').toUpperCase(), fontSize: 9 }
                  ],
                  border: [false, false, false, false]
                },
                { text: '', border: [false, false, false, false] },
                {
                  stack: [
                    { text: 'RAFAEL JOSE PÉREZ LEÓN', bold: true, fontSize: 10, margin: [0, 0, 0, 2] },
                    { text: 'PASAPORTE 112472838', fontSize: 9 }
                  ],
                  border: [false, false, false, false]
                }
              ],
              // Fila 2: Líneas de firma (exactamente a la misma altura)
              [
                {
                  stack: [
                    { canvas: [{ type: 'line', x1: 0, y1: 0, x2: 240, y2: 0, lineWidth: 0.5, lineColor: '#999' }], margin: [0, 20, 0, 3] },
                    { text: 'FIRMA', fontSize: 8, color: '#999', alignment: 'center' }
                  ],
                  border: [false, false, false, false]
                },
                { text: '', border: [false, false, false, false] },
                {
                  stack: [
                    { canvas: [{ type: 'line', x1: 0, y1: 0, x2: 240, y2: 0, lineWidth: 0.5, lineColor: '#999' }], margin: [0, 20, 0, 3] },
                    { text: 'FIRMA', fontSize: 8, color: '#999', alignment: 'center' }
                  ],
                  border: [false, false, false, false]
                }
              ]
            ]
          },
          layout: 'noBorders',
          margin: [0, 0, 0, 0]
        }
      ],
      styles: estilos
    };
  }

  try {
    const pdfDoc = pdfMake.createPdf(documentDefinition);
    if (soloVista) {
      pdfDoc.open();
    } else {
      pdfDoc.download(`${tipo === 'cotizacion' ? 'Cotizacion' : 'Cobro'}_${datos.numero}.pdf`);
    }
  } catch (error) {
    console.error("ERROR GENERANDO PDF:", error);
    alert("Hubo un error al crear el PDF. Revisa la consola para más detalles.");
  }
};